export default async function extension() {
  const {i18n} = shopify;

  const query = 'number_of_orders = 1 AND products_purchased MATCHES (id = product_id)';
  const queryToInsert = 'number_of_orders = 1 AND products_purchased MATCHES (id = | )';

  return [{
    title: i18n.translate('title'),
    description: i18n.translate('description'),
    createdOn: new Date('2023-08-15').toISOString(),
    query,
    queryToInsert
  }];
}
